export const adminDashboardDesign = {
  colors: {
    sidebar: "bg-gray-900 text-white",
    navbar: "bg-white shadow-md",
    overlay: "bg-black/40",
    hover: "hover:bg-gray-800",
    toggleBtn: "text-gray-700 hover:text-indigo-600 transition",
  },

  layout: {
    wrapper: "flex min-h-screen bg-gray-100",

    // Sidebar
    sidebar:
      "fixed top-0 left-0 h-full w-64 p-6 space-y-6 z-50 md:static md:translate-x-0",

    // Right content wrapper
    contentWrapper: "flex-1 flex flex-col w-full",

    // Push content on desktop
    desktopSpacing: "md:ml-64",

    // Navbar
    navbar:
      "h-16 flex items-center justify-between px-6 bg-white shadow-md",

    // Main content
    content: "p-6",

    // Sidebar nav item
    navItem:
      "px-3 py-2 rounded-lg transition cursor-pointer text-sm font-medium",
  },
};
